 22→var enrichCmd = &cobra.Command{
 23→	Use:   "enrich",
 24→	Short: "Enrich contacts with missing data from external providers",
 25→	Long:  "Fill missing contact fields (title, company, phone, etc.) using a waterfall of data providers.\nProviders are defined as YAML files for pluggability.",
 26→	RunE: func(cmd *cobra.Command, args []string) error {
 27→		if !enrichStats && !enrichBatch && enrichProspect == "" {
 28→			return cmd.Help()
 29→		}
 30→
 31→		d, err := db.Open()
 32→		if err != nil {
 33→			return err
 34→		}
 35→		defer d.Close()
 36→
 37→		if enrichStats {
 38→			return runEnrichStats(d)
 39→		}
 40→
 41→		if enrichProspect != "" {
 42→			return runEnrichProspect(d, enrichProspect)
 43→		}
 44→
 45→		if enrichBatch {
 46→			return runEnrichBatch(d, enrichLimit)
 47→		}
 48→
 49→		return nil
 50→	},
