 53→func runEnrichProspect(d *sql.DB, email string) error {
 54→	result, err := enrich.Enrich(d, enrich.EnrichRequest{ContactEmail: email})
 55→	if err != nil {
 56→		return err
 57→	}
 58→
 59→	if enrichFormat == "json" {
 60→		enc := json.NewEncoder(os.Stdout)
 61→		enc.SetIndent("", "  ")
 62→		return enc.Encode(result)
 63→	}
 64→
 65→	fmt.Printf("  Enrichment: %s\n", result.ContactEmail)
 66→	if len(result.FieldsFilled) > 0 {
 67→		fmt.Printf("  Filled:\n")
 68→		for f, v := range result.FieldsFilled {
 69→			fmt.Printf("    %s: %s\n", f, v)
 70→		}
 71→	}
 72→	if len(result.FieldsMissing) > 0 {
 73→		fmt.Printf("  Still missing: %v\n", result.FieldsMissing)
 74→	}
 75→	if len(result.ProvidersUsed) > 0 {
 76→		fmt.Printf("  Providers: %v\n", result.ProvidersUsed)
 77→	}
 78→	if result.Cached > 0 {
 79→		fmt.Printf("  Cached hits: %d\n", result.Cached)
 80→	}
 81→	if result.TotalCost > 0 {
 82→		fmt.Printf("  Est. cost: $%.4f\n", result.TotalCost)
 83→	}
 84→	return nil
 85→}
