 87→func runEnrichBatch(d *sql.DB, limit int) error {
 88→	results, err := enrich.BatchEnrich(d, limit)
 89→	if err != nil {
 90→		return err
 91→	}
 92→
 93→	if enrichFormat == "json" {
 94→		enc := json.NewEncoder(os.Stdout)
 95→		enc.SetIndent("", "  ")
 96→		return enc.Encode(results)
 97→	}
 98→
 99→	if len(results) == 0 {
100→		fmt.Println("  No contacts to enrich.")
101→		return nil
102→	}
103→
104→	totalFilled := 0
105→	totalMissing := 0
106→	totalCached := 0
107→	var totalCost float64
108→	for _, r := range results {
109→		totalFilled += len(r.FieldsFilled)
110→		totalMissing += len(r.FieldsMissing)
111→		totalCached += r.Cached
112→		totalCost += r.TotalCost
113→	}
114→
115→	fmt.Printf("  Enriched %d contact(s):\n", len(results))
116→	fmt.Printf("    Fields filled: %d\n", totalFilled)
117→	fmt.Printf("    Fields missing: %d\n", totalMissing)
118→	fmt.Printf("    Cache hits: %d\n", totalCached)
119→	if totalCost > 0 {
120→		fmt.Printf("    Est. cost: $%.4f\n", totalCost)
121→	}
122→	return nil
123→}
