125→func runEnrichStats(d *sql.DB) error {
126→	stats, err := enrich.Stats(d)
127→	if err != nil {
128→		return err
129→	}
130→
131→	if enrichFormat == "json" {
132→		enc := json.NewEncoder(os.Stdout)
133→		enc.SetIndent("", "  ")
134→		return enc.Encode(stats)
135→	}
136→
137→	fmt.Printf("  Enrichment Coverage (%d contacts)\n", stats.TotalContacts)
138→	fmt.Printf("  ──────────────────────────────────\n")
139→	fmt.Printf("  Enriched:    %d\n", stats.Enriched)
140→	fmt.Printf("  Unenriched:  %d\n", stats.Unenriched)
141→	fmt.Println()
142→	fmt.Println("  Field Coverage:")
143→	for _, field := range enrich.AllEnrichableFields() {
144→		count := stats.FieldCoverage[field]
