171→
172→	// 1. LinkedIn via Convex/Unipile
173→	fmt.Fprintf(os.Stderr, "  Fetching LinkedIn data for %s...\n", slug)
174→	linkedinData, err := client.EnrichCompany(af.Token, slug)
175→	if err != nil {
176→		fmt.Fprintf(os.Stderr, "  \033[33m!\033[0m LinkedIn: %s\n", err)
177→		linkedinData = []byte("{}")
178→	} else {
179→		var li struct {
180→			EmployeeCountActual int `json:"employee_count_actual"`
181→		}
182→		json.Unmarshal(linkedinData, &li)
183→		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m LinkedIn: %d employees found\n", li.EmployeeCountActual)
