186→	// 2. Hacker News
187→	fmt.Fprintf(os.Stderr, "  Searching Hacker News...\n")
188→	hnResult, hnErr := enrich.SearchHackerNews(slug, 10)
189→	if hnErr != nil {
190→		fmt.Fprintf(os.Stderr, "  \033[33m!\033[0m HN: %s\n", hnErr)
191→	} else if hnResult != nil && hnResult.Total > 0 {
192→		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m HN: %d mentions\n", hnResult.Total)
193→	} else {
194→		fmt.Fprintf(os.Stderr, "  \033[90m-\033[0m No HN mentions\n")
195→	}
196→
197→	// 3. GitHub
198→	fmt.Fprintf(os.Stderr, "  Checking GitHub...\n")
199→	ghResult, ghErr := enrich.FetchGitHubOrg(slug)
200→	if ghErr != nil {
201→		fmt.Fprintf(os.Stderr, "  \033[33m!\033[0m GitHub: %s\n", ghErr)
202→	} else if ghResult != nil {
203→		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m GitHub: %d public repos\n", ghResult.PublicRepos)
204→	} else {
205→		fmt.Fprintf(os.Stderr, "  \033[90m-\033[0m No GitHub org\n")
206→	}
207→
208→	// 4. Wikipedia
209→	fmt.Fprintf(os.Stderr, "  Checking Wikipedia...\n")
210→	wikiResult, wikiErr := enrich.FetchWikipedia(slug)
211→	if wikiErr != nil {
212→		fmt.Fprintf(os.Stderr, "  \033[33m!\033[0m Wikipedia: %s\n", wikiErr)
213→	} else if wikiResult != nil {
214→		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Wikipedia page found\n")
215→	} else {
216→		fmt.Fprintf(os.Stderr, "  \033[90m-\033[0m No Wikipedia page\n")
217→	}
218→
219→	// Combine into single output
220→	combined := map[string]interface{}{
221→		"linkedin": json.RawMessage(linkedinData),
222→	}
223→	if hnResult != nil {
224→		combined["hackernews"] = hnResult
225→	}
226→	if ghResult != nil {
227→		combined["github"] = ghResult
228→	}
229→	if wikiResult != nil {
230→		combined["wikipedia"] = wikiResult
231→	}
232→
233→	if enrichFormat == "json" {
234→		out, _ := json.MarshalIndent(combined, "", "  ")
235→		fmt.Println(string(out))
236→	} else {
237→		printCompanySummary(linkedinData, hnResult, ghResult, wikiResult)
