397→func extractLinkedInSlug(input, pathSegment string) string {
398→	if strings.Contains(input, "linkedin.com/"+pathSegment+"/") {
399→		parts := strings.Split(strings.TrimRight(input, "/"), "/"+pathSegment+"/")
400→		if len(parts) > 1 {
401→			return strings.Split(parts[1], "/")[0]
402→		}
403→	}
404→	return input
405→}
