186→	// Collect providers used
187→	for p := range providersUsedSet {
188→		result.ProvidersUsed = append(result.ProvidersUsed, p)
189→	}
190→
191→	// Update contacts table with any filled fields
192→	if len(result.FieldsFilled) > 0 {
193→		if err := updateContactFields(db, req.ContactEmail, result.FieldsFilled, result.ProvidersUsed); err != nil {
