201→// BatchEnrich finds unenriched contacts and enriches them.
202→func BatchEnrich(db *sql.DB, limit int) ([]EnrichResult, error) {
203→	rows, err := db.Query(`
204→		SELECT email FROM contacts
205→		WHERE enriched_at = '' OR enriched_at IS NULL
206→		ORDER BY created_at DESC
207→		LIMIT ?
208→	`, limit)
209→	if err != nil {
210→		return nil, fmt.Errorf("querying unenriched contacts: %w", err)
211→	}
212→	defer rows.Close()
213→
214→	var emails []string
215→	for rows.Next() {
216→		var email string
217→		if err := rows.Scan(&email); err != nil {
218→			continue
219→		}
220→		emails = append(emails, email)
221→	}
222→	if err := rows.Err(); err != nil {
223→		return nil, fmt.Errorf("scanning unenriched contacts: %w", err)
224→	}
225→
226→	var results []EnrichResult
227→	for _, email := range emails {
228→		r, err := Enrich(db, EnrichRequest{ContactEmail: email})
229→		if err != nil {
230→			log.Printf("enrich: skipping %s: %v", email, err)
231→			continue
232→		}
233→		results = append(results, *r)
234→	}
235→
236→	return results, nil
237→}
