243→	}
244→
245→	// Total contacts
246→	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts`).Scan(&stats.TotalContacts); err != nil {
247→		return nil, fmt.Errorf("counting contacts: %w", err)
248→	}
