250→	// Enriched contacts (have enriched_at set)
251→	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts WHERE enriched_at != '' AND enriched_at IS NOT NULL`).Scan(&stats.Enriched); err != nil {
252→		return nil, fmt.Errorf("counting enriched contacts: %w", err)
253→	}
254→	stats.Unenriched = stats.TotalContacts - stats.Enriched
255→
256→	// Per-field coverage
