 13→// Provider defines an enrichment data source loaded from YAML.
 14→type Provider struct {
 15→	Name           string            `yaml:"name"`
 16→	Type           string            `yaml:"provider"` // apify, apollo, http
 17→	Endpoint       string            `yaml:"endpoint,omitempty"`
 18→	ActorID        string            `yaml:"actor_id,omitempty"`
 19→	CostPerCall    float64           `yaml:"cost_per_call"`
 20→	FieldsProvided []string          `yaml:"fields_provided"`
 21→	InputType      string            `yaml:"input_type"` // email, linkedin_url, name_company, domain
 22→	InputMapping   map[string]string `yaml:"input_mapping"`
 23→	OutputMapping  map[string]string `yaml:"output_mapping"`
 24→	CacheTTL       string            `yaml:"cache_ttl"` // e.g., "168h"
 25→}
 26→
 27→// ProviderRegistry holds all loaded providers keyed by name.
 28→type ProviderRegistry struct {
 29→	providers map[string]Provider
 30→}
 31→
 32→// LoadProviders scans bundled provider YAMLs from internal/enrich/providers/
 33→// and user-defined YAMLs from .nurge/providers/. User definitions override
 34→// bundled ones by name.
 35→func LoadProviders() (*ProviderRegistry, error) {
 36→	reg := &ProviderRegistry{
 37→		providers: make(map[string]Provider),
 38→	}
 39→
 40→	// 1. Load bundled providers
 41→	entries, err := fs.ReadDir(bundledProviders, "providers")
 42→	if err != nil {
 43→		return nil, fmt.Errorf("reading bundled providers: %w", err)
 44→	}
 45→	for _, entry := range entries {
 46→		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
 47→			continue
 48→		}
 49→		data, err := bundledProviders.ReadFile("providers/" + entry.Name())
 50→		if err != nil {
 51→			continue
 52→		}
 53→		var p Provider
 54→		if err := yaml.Unmarshal(data, &p); err != nil {
 55→			continue // skip invalid bundled defs
 56→		}
 57→		if p.Name == "" {
 58→			continue
 59→		}
 60→		reg.providers[p.Name] = p
 61→	}
 62→
 63→	// 2. Load project-local providers from .nurge/providers/
 64→	localDir := filepath.Join(".nurge", "providers")
 65→	localEntries, err := os.ReadDir(localDir)
 66→	if err == nil { // silently skip if dir doesn't exist
 67→		for _, entry := range localEntries {
 68→			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
 69→				continue
 70→			}
 71→			data, err := os.ReadFile(filepath.Join(localDir, entry.Name()))
 72→			if err != nil {
 73→				continue
 74→			}
 75→			var p Provider
 76→			if err := yaml.Unmarshal(data, &p); err != nil {
 77→				continue
 78→			}
 79→			if p.Name == "" {
 80→				continue
 81→			}
 82→			reg.providers[p.Name] = p
 83→		}
 84→	}
 85→
 86→	return reg, nil
 87→}
 88→
 89→// GetProvider returns a provider by name, or false if not found.
 90→func (r *ProviderRegistry) GetProvider(name string) (Provider, bool) {
 91→	p, ok := r.providers[name]
 92→	return p, ok
 93→}
 94→
 95→// ProvidersForField returns all providers that can fill a given field.
 96→func (r *ProviderRegistry) ProvidersForField(field string) []Provider {
 97→	var result []Provider
 98→	for _, p := range r.providers {
 99→		for _, f := range p.FieldsProvided {
100→			if f == field {
101→				result = append(result, p)
102→				break
103→			}
104→		}
105→	}
106→	return result
107→}
108→
109→// All returns all loaded providers.
110→func (r *ProviderRegistry) All() map[string]Provider {
111→	out := make(map[string]Provider, len(r.providers))
112→	for k, v := range r.providers {
113→		out[k] = v
114→	}
115→	return out
116→}
117→
118→// Count returns the number of loaded providers.
119→func (r *ProviderRegistry) Count() int {
120→	return len(r.providers)
121→}
