// EnrichRequest specifies what to enrich and how.
type EnrichRequest struct {
	ContactEmail string   // required: the contact to enrich
	Fields       []string // specific fields to enrich, or empty for all missing
	Providers    []string // specific providers to use, or empty for waterfall
}

// EnrichResult summarizes what happened.
type EnrichResult struct {
	ContactEmail  string            `json:"contact_email"`
	FieldsFilled  map[string]string `json:"fields_filled"`
	FieldsMissing []string          `json:"fields_missing"`
	ProvidersUsed []string          `json:"providers_used"`
	TotalCost     float64           `json:"total_cost"`
	Cached        int               `json:"cached"`
}

// EnrichStats shows enrichment coverage across all contacts.
type EnrichStats struct {
	TotalContacts int            `json:"total_contacts"`
	Enriched      int            `json:"enriched"`
	Unenriched    int            `json:"unenriched"`
	FieldCoverage map[string]int `json:"field_coverage"`
}

// contactRow holds the fields we read/write on the contacts table.
type contactRow struct {
	Email        string
	Name         string
	Title        string
	Company      string
	Phone        string
	Domain       string
	Industry     string
	CompanySize  string
	FundingStage string
	LinkedInURL  string
	Website      string
	EnrichedAt   string
	Sources      string // JSON array
}

// enrichableColumns maps field names to their contacts table column names.
var enrichableColumns = map[string]string{
	"email":         "email",
	"name":          "name",
	"title":         "title",
	"company":       "company",
	"phone":         "phone",
	"industry":      "industry",
	"company_size":  "company_size",
	"funding_stage": "funding_stage",
	"website":       "website",
	"linkedin_url":  "linkedin_url",
}

// Enrich enriches a single contact, filling missing fields via the waterfall.
func Enrich(db *sql.DB, req EnrichRequest) (*EnrichResult, error) {
	if req.ContactEmail == "" {
		return nil, fmt.Errorf("contact email is required")
	}

	// Load provider registry
	registry, err := LoadProviders()
	if err != nil {
		return nil, fmt.Errorf("loading providers: %w", err)
	}

	// Load contact from DB
	contact, err := loadContact(db, req.ContactEmail)
	if err != nil {
		return nil, fmt.Errorf("loading contact %s: %w", req.ContactEmail, err)
	}

	// Determine which fields need enrichment
	currentValues := contact.fieldMap()
	var targetFields []string
	if len(req.Fields) > 0 {
		targetFields = req.Fields
	} else {
		targetFields = AllEnrichableFields()
	}

	var missingFields []string
	for _, f := range targetFields {
		if val, ok := currentValues[f]; !ok || val == "" {
			missingFields = append(missingFields, f)
		}
	}

	result := &EnrichResult{
		ContactEmail: req.ContactEmail,
		FieldsFilled: make(map[string]string),
	}

	if len(missingFields) == 0 {
		return result, nil
	}

	providersUsedSet := make(map[string]bool)

	// For each missing field, try providers in waterfall order
	for _, field := range missingFields {
		var providerNames []string
		if len(req.Providers) > 0 {
			// Use explicitly requested providers
			providerNames = req.Providers
		} else {
			// Use default waterfall
			providerNames = WaterfallForField(field)
		}

		filled := false
		for _, provName := range providerNames {
			provider, ok := registry.GetProvider(provName)
			if !ok {
				continue
			}

			// Check if this provider can fill this field
			canFill := false
			for _, pf := range provider.FieldsProvided {
				if pf == field {
					canFill = true
					break
				}
			}
			if !canFill {
				continue
			}

			// Build cache key from provider + contact input
			cacheInput := buildCacheInput(provider, contact)
			cacheKey, err := assembly.CacheKey(provName, cacheInput)
			if err != nil {
				continue
			}

			// Check cache first
			cached, err := assembly.GetCached(db, provName, cacheKey)
			if err != nil {
				log.Printf("cache lookup error for %s/%s: %v", provName, field, err)
				continue
			}

			if cached != nil {
				// Extract field value from cached output
				var outputMap map[string]string
				if err := json.Unmarshal(cached.OutputData, &outputMap); err == nil {
					if val, ok := outputMap[field]; ok && val != "" {
						result.FieldsFilled[field] = val
						result.Cached++
						providersUsedSet[provName] = true
						filled = true
						break
					}
				}
			}

			// Not cached -- this is where a real API call would go.
			// For now, log what WOULD happen and leave the field missing.
			log.Printf("enrich: would call provider %q (type=%s) to fill %q for %s",
				provName, provider.Type, field, req.ContactEmail)
			result.TotalCost += provider.CostPerCall
			providersUsedSet[provName] = true
		}

		if !filled {
			result.FieldsMissing = append(result.FieldsMissing, field)
		}
	}

	// Collect providers used
	for p := range providersUsedSet {
		result.ProvidersUsed = append(result.ProvidersUsed, p)
	}

	// Update contacts table with any filled fields
	if len(result.FieldsFilled) > 0 {
		if err := updateContactFields(db, req.ContactEmail, result.FieldsFilled, result.ProvidersUsed); err != nil {
			return result, fmt.Errorf("updating contact: %w", err)
		}
	}

	return result, nil
}

// BatchEnrich finds unenriched contacts and enriches them.
func BatchEnrich(db *sql.DB, limit int) ([]EnrichResult, error) {
	rows, err := db.Query(`
		SELECT email FROM contacts
		WHERE enriched_at = '' OR enriched_at IS NULL
		ORDER BY created_at DESC
		LIMIT ?
	`, limit)
	if err != nil {
		return nil, fmt.Errorf("querying unenriched contacts: %w", err)
	}
	defer rows.Close()

	var emails []string
	for rows.Next() {
		var email string
		if err := rows.Scan(&email); err != nil {
			continue
		}
		emails = append(emails, email)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("scanning unenriched contacts: %w", err)
	}

	var results []EnrichResult
	for _, email := range emails {
		r, err := Enrich(db, EnrichRequest{ContactEmail: email})
		if err != nil {
			log.Printf("enrich: skipping %s: %v", email, err)
			continue
		}
		results = append(results, *r)
	}

	return results, nil
}

// Stats returns enrichment coverage across all contacts.
func Stats(db *sql.DB) (*EnrichStats, error) {
	stats := &EnrichStats{
		FieldCoverage: make(map[string]int),
	}

	// Total contacts
	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts`).Scan(&stats.TotalContacts); err != nil {
		return nil, fmt.Errorf("counting contacts: %w", err)
	}

	// Enriched contacts (have enriched_at set)
	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts WHERE enriched_at != '' AND enriched_at IS NOT NULL`).Scan(&stats.Enriched); err != nil {
		return nil, fmt.Errorf("counting enriched contacts: %w", err)
	}
	stats.Unenriched = stats.TotalContacts - stats.Enriched

	// Per-field coverage
	fieldColumns := map[string]string{
		"email":         "email",
		"name":          "name",
		"title":         "title",
		"company":       "company",
		"phone":         "phone",
		"industry":      "industry",
		"company_size":  "company_size",
		"funding_stage": "funding_stage",
		"website":       "website",
		"linkedin_url":  "linkedin_url",
	}
	for field, col := range fieldColumns {
		var count int
		query := fmt.Sprintf(`SELECT COUNT(*) FROM contacts WHERE %s != '' AND %s IS NOT NULL`, col, col)
		if err := db.QueryRow(query).Scan(&count); err != nil {
			continue
		}
		stats.FieldCoverage[field] = count
	}

	return stats, nil
}

// loadContact reads a contact from the DB.
func loadContact(db *sql.DB, email string) (*contactRow, error) {
	c := &contactRow{}
	err := db.QueryRow(`
		SELECT email, name, title, company, phone, domain,
		       COALESCE(industry, ''), COALESCE(company_size, ''),
		       COALESCE(funding_stage, ''), COALESCE(linkedin_url, ''),
		       COALESCE(website, ''), COALESCE(enriched_at, ''),
		       COALESCE(enrichment_sources, '[]')
		FROM contacts WHERE email = ?
	`, email).Scan(
		&c.Email, &c.Name, &c.Title, &c.Company, &c.Phone, &c.Domain,
		&c.Industry, &c.CompanySize, &c.FundingStage, &c.LinkedInURL,
		&c.Website, &c.EnrichedAt, &c.Sources,
	)
	if err == sql.ErrNoRows {
		return nil, fmt.Errorf("contact not found: %s", email)
	}
	if err != nil {
		return nil, err
	}
	return c, nil
}

// fieldMap returns current non-empty field values.
func (c *contactRow) fieldMap() map[string]string {
	return map[string]string{
		"email":         c.Email,
		"name":          c.Name,
		"title":         c.Title,
		"company":       c.Company,
		"phone":         c.Phone,
		"industry":      c.Industry,
		"company_size":  c.CompanySize,
		"funding_stage": c.FundingStage,
		"website":       c.Website,
		"linkedin_url":  c.LinkedInURL,
	}
}

// buildCacheInput constructs the input data for cache key generation
// based on the provider's input_type and the contact's available data.
func buildCacheInput(provider Provider, contact *contactRow) map[string]string {
	input := make(map[string]string)
	switch provider.InputType {
	case "email":
		input["email"] = contact.Email
	case "linkedin_url":
		input["linkedin_url"] = contact.LinkedInURL
	case "name_company":
		input["name"] = contact.Name
		input["company"] = contact.Company
	case "domain":
		input["domain"] = contact.Domain
	}
	return input
}

// updateContactFields writes filled fields back to the contacts table
// and updates enriched_at and enrichment_sources.
func updateContactFields(db *sql.DB, email string, fields map[string]string, providers []string) error {
	var setClauses []string
	var args []any

	for field, value := range fields {
		col, ok := enrichableColumns[field]
		if !ok {
			continue
		}
		setClauses = append(setClauses, fmt.Sprintf("%s = ?", col))
		args = append(args, value)
	}

	if len(setClauses) == 0 {
		return nil
	}

	// Update enriched_at
	setClauses = append(setClauses, "enriched_at = ?")
	args = append(args, time.Now().UTC().Format("2006-01-02 15:04:05"))

	// Merge enrichment_sources
	sourcesJSON, _ := json.Marshal(providers)
	setClauses = append(setClauses, "enrichment_sources = ?")
	args = append(args, string(sourcesJSON))

	// updated_at
	setClauses = append(setClauses, "updated_at = datetime('now')")

	args = append(args, email)

	query := fmt.Sprintf("UPDATE contacts SET %s WHERE email = ?", strings.Join(setClauses, ", "))
	_, err := db.Exec(query, args...)
	return err
}

