package cmd

import (
	"encoding/json"
	"fmt"
	"io"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/enrich"
)

var enrichFormat string

var enrichCmd = &cobra.Command{
	Use:   "enrich",
	Short: "Enrich contact data from external sources",
}

var enrichSaveCmd = &cobra.Command{
	Use:   "save",
	Short: "Save enrichment results from stdin",
	Long: `Reads enrichment JSON from stdin and updates contacts + enrichment cache.

Accepts a single object or an array of objects:
  {
    "contact_email": "person@company.com",
    "fields": {
      "name": "John Doe",
      "title": "CTO",
      "company": "Acme Inc",
      "phone": "+1234567890"
    },
    "source": "manual",
    "provider": "clearbit"
  }

Fields mapped to contacts table: name, title, company, phone, domain.
Extra fields (industry, company_size, funding_stage, linkedin_url, website) are
stored in enrichment_cache when a provider is specified.

Use --stdin flag to read from stdin (required).`,
	RunE: func(cmd *cobra.Command, args []string) error {
		stdin, _ := cmd.Flags().GetBool("stdin")
		if !stdin {
			return fmt.Errorf("--stdin flag is required")
		}

		data, err := io.ReadAll(os.Stdin)
		if err != nil {
			return fmt.Errorf("reading stdin: %w", err)
		}

		// Try to parse as array first, then as single object.
		var inputs []enrich.SaveInput
		if err := json.Unmarshal(data, &inputs); err != nil {
			var single enrich.SaveInput
			if err2 := json.Unmarshal(data, &single); err2 != nil {
				return fmt.Errorf("parsing stdin JSON: %w", err)
			}
			inputs = []enrich.SaveInput{single}
		}

		if len(inputs) == 0 {
			return fmt.Errorf("no enrichment data provided")
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		results := enrich.SaveBatch(d, inputs)

		if enrichFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(results)
		}

		// Human-readable output.
		var updated, cached, errCount int
		for _, r := range results {
			if r.Error != "" {
				errCount++
				fmt.Fprintf(os.Stderr, "  error: %s: %s\n", r.ContactEmail, r.Error)
				continue
			}
			if r.ContactUpdated {
				updated++
			}
			if r.CacheStored {
				cached++
			}
		}

		fmt.Printf("  Processed %d enrichment(s): %d contact(s) updated, %d cached", len(results), updated, cached)
		if errCount > 0 {
			fmt.Printf(", %d error(s)", errCount)
		}
		fmt.Println()

		return nil
	},
}

func init() {
	enrichCmd.PersistentFlags().StringVar(&enrichFormat, "format", "", "Output format (json)")
	enrichSaveCmd.Flags().Bool("stdin", false, "Read enrichment data from stdin (required)")
	enrichCmd.AddCommand(enrichSaveCmd)
	rootCmd.AddCommand(enrichCmd)
}

