func extractLinkedInSlug(input, pathSegment string) string {
	if strings.Contains(input, "linkedin.com/"+pathSegment+"/") {
		parts := strings.Split(strings.TrimRight(input, "/"), "/"+pathSegment+"/")
		if len(parts) > 1 {
			return strings.Split(parts[1], "/")[0]
		}
	}
	return input
}

func printCompanySummary(linkedinData []byte, hn *enrich.HackerNewsResult, gh *enrich.GitHubOrg, wiki *enrich.WikipediaSummary) {
	var li struct {
		Company struct {
			Name          string   `json:"name"`
			EmployeeCount int      `json:"employee_count"`
			Industry      []string `json:"industry"`
			Website       string   `json:"website"`
			Founded       string   `json:"founded"`
			Followers     int      `json:"followers"`
			Tagline       string   `json:"tagline"`
			Hashtags      []string `json:"hashtags"`
		} `json:"company"`
		Employees []struct {
			Name     string `json:"name"`
			Headline string `json:"headline"`
			Location string `json:"location"`
		} `json:"employees"`
		EmployeeCountActual int `json:"employee_count_actual"`
	}
	json.Unmarshal(linkedinData, &li)

	fmt.Printf("\n  === %s ===\n", li.Company.Name)
	if li.Company.Tagline != "" {
		fmt.Printf("  %s\n", li.Company.Tagline)
	}
	fmt.Printf("  %s | %s | Founded %s\n", strings.Join(li.Company.Industry, ", "), li.Company.Website, li.Company.Founded)
	fmt.Printf("  %d employees | %d followers\n", li.Company.EmployeeCount, li.Company.Followers)

	if len(li.Employees) > 0 {
		fmt.Printf("\n  Team (%d found):\n", li.EmployeeCountActual)
		for _, e := range li.Employees {
			h := e.Headline
			if len(h) > 65 {
				h = h[:65] + "..."
			}
			fmt.Printf("  - %s | %s | %s\n", e.Name, h, e.Location)
		}
	}

	if gh != nil && gh.PublicRepos > 0 {
		fmt.Printf("\n  GitHub: %d repos\n", gh.PublicRepos)
		for _, r := range gh.Repos {
			if r.Stars > 0 {
				fmt.Printf("  - %s (%s) %d stars\n", r.Name, r.Language, r.Stars)
			}
		}
	}

	if hn != nil && hn.Total > 0 {
		fmt.Printf("\n  Hacker News: %d mentions\n", hn.Total)
		for _, m := range hn.Mentions {
			if m.Points > 5 {
				fmt.Printf("  - %s (%d pts)\n", m.Title, m.Points)
			}
		}
	}

	if wiki != nil {
		extract := wiki.Extract
		if len(extract) > 200 {
			extract = extract[:200] + "..."
		}
		fmt.Printf("\n  Wikipedia: %s\n", extract)
	}
	fmt.Println()
}

