package cmd

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/enrich"
)

var enrichFormat string
var enrichProspect string
var enrichBatch bool
var enrichLimit int
var enrichStats bool

var enrichCmd = &cobra.Command{
	Use:   "enrich",
	Short: "Enrich contacts with missing data from external providers",
	Long:  "Fill missing contact fields (title, company, phone, etc.) using a waterfall of data providers.\nProviders are defined as YAML files for pluggability.",
	RunE: func(cmd *cobra.Command, args []string) error {
		if !enrichStats && !enrichBatch && enrichProspect == "" {
			return cmd.Help()
		}

		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if enrichStats {
			return runEnrichStats(d)
		}

		if enrichProspect != "" {
			return runEnrichProspect(d, enrichProspect)
		}

		if enrichBatch {
			return runEnrichBatch(d, enrichLimit)
		}

		return nil
	},
}

func runEnrichProspect(d *sql.DB, email string) error {
	result, err := enrich.Enrich(d, enrich.EnrichRequest{ContactEmail: email})
	if err != nil {
		return err
	}

	if enrichFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(result)
	}

	fmt.Printf("  Enrichment: %s\n", result.ContactEmail)
	if len(result.FieldsFilled) > 0 {
		fmt.Printf("  Filled:\n")
		for f, v := range result.FieldsFilled {
			fmt.Printf("    %s: %s\n", f, v)
		}
	}
	if len(result.FieldsMissing) > 0 {
		fmt.Printf("  Still missing: %v\n", result.FieldsMissing)
	}
	if len(result.ProvidersUsed) > 0 {
		fmt.Printf("  Providers: %v\n", result.ProvidersUsed)
	}
	if result.Cached > 0 {
		fmt.Printf("  Cached hits: %d\n", result.Cached)
	}
	if result.TotalCost > 0 {
		fmt.Printf("  Est. cost: $%.4f\n", result.TotalCost)
	}
	return nil
}

func runEnrichBatch(d *sql.DB, limit int) error {
	results, err := enrich.BatchEnrich(d, limit)
	if err != nil {
		return err
	}

	if enrichFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(results)
	}

	if len(results) == 0 {
		fmt.Println("  No contacts to enrich.")
		return nil
	}

	totalFilled := 0
	totalMissing := 0
	totalCached := 0
	var totalCost float64
	for _, r := range results {
		totalFilled += len(r.FieldsFilled)
		totalMissing += len(r.FieldsMissing)
		totalCached += r.Cached
		totalCost += r.TotalCost
	}

	fmt.Printf("  Enriched %d contact(s):\n", len(results))
	fmt.Printf("    Fields filled: %d\n", totalFilled)
	fmt.Printf("    Fields missing: %d\n", totalMissing)
	fmt.Printf("    Cache hits: %d\n", totalCached)
	if totalCost > 0 {
		fmt.Printf("    Est. cost: $%.4f\n", totalCost)
	}
	return nil
}

func runEnrichStats(d *sql.DB) error {
	stats, err := enrich.Stats(d)
	if err != nil {
		return err
	}

	if enrichFormat == "json" {
		enc := json.NewEncoder(os.Stdout)
		enc.SetIndent("", "  ")
		return enc.Encode(stats)
	}

	fmt.Printf("  Enrichment Coverage (%d contacts)\n", stats.TotalContacts)
	fmt.Printf("  ──────────────────────────────────\n")
	fmt.Printf("  Enriched:    %d\n", stats.Enriched)
	fmt.Printf("  Unenriched:  %d\n", stats.Unenriched)
	fmt.Println()
	fmt.Println("  Field Coverage:")
	for _, field := range enrich.AllEnrichableFields() {
		count := stats.FieldCoverage[field]
		pct := 0.0
		if stats.TotalContacts > 0 {
			pct = float64(count) / float64(stats.TotalContacts) * 100
		}
		fmt.Printf("    %-15s %d (%.0f%%)\n", field, count, pct)
	}
	return nil
}

// nurge enrich company <slug>
var enrichCompanyCmd = &cobra.Command{
	Use:   "company <linkedin-slug-or-url>",
	Short: "Get company profile + all employees from LinkedIn, plus free sources",
	Args:  cobra.ExactArgs(1),
	RunE:  runEnrichCompany,
}

func runEnrichCompany(cmd *cobra.Command, args []string) error {
	slug := extractLinkedInSlug(args[0], "company")

	af, err := account.LoadAuth()
	if err != nil || af.Token == "" {
		return fmt.Errorf("not logged in. Run: nurge account login")
	}

	client := account.NewConvexClient(GetConvexURL())

	// 1. LinkedIn via Convex/Unipile
	fmt.Fprintf(os.Stderr, "  Fetching LinkedIn data for %s...\n", slug)
	linkedinData, err := client.EnrichCompany(af.Token, slug)
	if err != nil {
		fmt.Fprintf(os.Stderr, "  \033[33m!\033[0m LinkedIn: %s\n", err)
		linkedinData = []byte("{}")
	} else {
		var li struct {
			EmployeeCountActual int `json:"employee_count_actual"`
		}
		json.Unmarshal(linkedinData, &li)
		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m LinkedIn: %d employees found\n", li.EmployeeCountActual)
	}

	// 2. Hacker News
	fmt.Fprintf(os.Stderr, "  Searching Hacker News...\n")
	hnResult, hnErr := enrich.SearchHackerNews(slug, 10)
	if hnErr != nil {
		fmt.Fprintf(os.Stderr, "  \033[33m!\033[0m HN: %s\n", hnErr)
	} else if hnResult != nil && hnResult.Total > 0 {
		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m HN: %d mentions\n", hnResult.Total)
	} else {
		fmt.Fprintf(os.Stderr, "  \033[90m-\033[0m No HN mentions\n")
	}

	// 3. GitHub
	fmt.Fprintf(os.Stderr, "  Checking GitHub...\n")
	ghResult, ghErr := enrich.FetchGitHubOrg(slug)
	if ghErr != nil {
		fmt.Fprintf(os.Stderr, "  \033[33m!\033[0m GitHub: %s\n", ghErr)
	} else if ghResult != nil {
		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m GitHub: %d public repos\n", ghResult.PublicRepos)
	} else {
		fmt.Fprintf(os.Stderr, "  \033[90m-\033[0m No GitHub org\n")
	}

	// 4. Wikipedia
	fmt.Fprintf(os.Stderr, "  Checking Wikipedia...\n")
	wikiResult, wikiErr := enrich.FetchWikipedia(slug)
	if wikiErr != nil {
		fmt.Fprintf(os.Stderr, "  \033[33m!\033[0m Wikipedia: %s\n", wikiErr)
	} else if wikiResult != nil {
		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Wikipedia page found\n")
	} else {
		fmt.Fprintf(os.Stderr, "  \033[90m-\033[0m No Wikipedia page\n")
	}

	// Combine into single output
	combined := map[string]interface{}{
		"linkedin": json.RawMessage(linkedinData),
	}
	if hnResult != nil {
		combined["hackernews"] = hnResult
	}
	if ghResult != nil {
		combined["github"] = ghResult
	}
	if wikiResult != nil {
		combined["wikipedia"] = wikiResult
	}

	if enrichFormat == "json" {
		out, _ := json.MarshalIndent(combined, "", "  ")
		fmt.Println(string(out))
	} else {
		printCompanySummary(linkedinData, hnResult, ghResult, wikiResult)
	}
	return nil
}

// nurge enrich person <identifier>
var enrichPersonCmd = &cobra.Command{
	Use:   "person <linkedin-identifier-or-url>",
	Short: "Get full LinkedIn profile for a person",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		identifier := extractLinkedInSlug(args[0], "in")

		af, err := account.LoadAuth()
		if err != nil || af.Token == "" {
			return fmt.Errorf("not logged in. Run: nurge account login")
		}

		client := account.NewConvexClient(GetConvexURL())

		fmt.Fprintf(os.Stderr, "  Fetching profile for %s...\n", identifier)
		data, err := client.EnrichPerson(af.Token, identifier)
		if err != nil {
			return fmt.Errorf("enrich failed: %w", err)
		}
		fmt.Fprintf(os.Stderr, "  \033[32m✓\033[0m Profile fetched\n")

